import fs from 'fs';const DATA_PATH='static/data/incidents.json';const X_USERNAME=process.env.X_USERNAME||'Global_Decipher';const TOKEN=process.env.X_BEARER_TOKEN||'';const API='https://api.twitter.com/2';const NUMBERS=new Map([['zero',0],['one',1],['two',2],['three',3],['four',4],['five',5],['six',6],['seven',7],['eight',8],['nine',9],['ten',10],['eleven',11],['twelve',12],['thirteen',13],['fourteen',14],['fifteen',15],['twenty',20],['thirty',30],['thirty-five',35]]);const DISTRICTS=[{terms:['bajaur','loi sam'],district:'Bajaur',province:'Khyber Pakhtunkhwa',lat:34.72,lng:71.5},{terms:['lakki','ghazni khel','darra tang'],district:'Lakki Marwat',province:'Khyber Pakhtunkhwa',lat:32.61,lng:70.91},{terms:['tank','wanda zalu','wanda zalo','wanda zulu'],district:'Tank',province:'Khyber Pakhtunkhwa',lat:32.22,lng:70.38},{terms:['wana','south waziristan'],district:'South Waziristan',province:'Khyber Pakhtunkhwa',lat:32.3,lng:69.57},{terms:['dera ismail khan','di khan'],district:'Dera Ismail Khan',province:'Khyber Pakhtunkhwa',lat:31.83,lng:70.9},{terms:['bannu'],district:'Bannu',province:'Khyber Pakhtunkhwa',lat:32.99,lng:70.6},{terms:['peshawar'],district:'Peshawar',province:'Khyber Pakhtunkhwa',lat:34.01,lng:71.56},{terms:['quetta','mangla zarghoon'],district:'Quetta',province:'Balochistan',lat:30.3,lng:67.2},{terms:['khuzdar'],district:'Khuzdar',province:'Balochistan',lat:27.8,lng:66.62},{terms:['kech','turbat'],district:'Kech',province:'Balochistan',lat:26,lng:63.05},{terms:['karachi'],district:'Karachi',province:'Sindh',lat:24.86,lng:67.01},{terms:['lahore'],district:'Lahore',province:'Punjab',lat:31.52,lng:74.36},{terms:['islamabad'],district:'Islamabad',province:'Islamabad',lat:33.68,lng:73.05},{terms:['gilgit'],district:'Gilgit',province:'Gilgit-Baltistan',lat:35.92,lng:74.31}];function out(name,value){if(process.env.GITHUB_OUTPUT)fs.appendFileSync(process.env.GITHUB_OUTPUT,`${name}=${value}\n`)}function compact(value){return String(value||'').replace(/https?:[^ ]+/g,'').split(' ').filter(Boolean).join(' ').trim()}function slug(value){return String(value||'').toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,56)}function lower(value){return String(value||'').toLowerCase()}function hasAny(text,terms){const l=lower(text);return terms.some((term)=>l.includes(term))}function tokens(text){return lower(text).replace(/[^a-z0-9-]+/g,' ').split(' ').filter(Boolean)}function toNumber(value){if(!value)return 0;if(/^[0-9]+$/.test(value))return Number(value);return NUMBERS.get(value)||0}function casualty(text,terms){const list=tokens(text);for(let i=0;i<list.length;i+=1){if(!terms.includes(list[i]))continue;for(let j=Math.max(0,i-6);j<=Math.min(list.length-1,i+2);j+=1){const n=toNumber(list[j]);if(n)return n}}return 0}function districtFor(text){return DISTRICTS.find((item)=>hasAny(text,item.terms))}function incidentLike(text){return hasAny(text,['attack','attacked','blast','explosion','ied','quadcopter','drone','killed','injured','wounded','operation','ibo','ambush','firing','militant','terrorist','security forces'])}function category(text){if(hasAny(text,['ied','blast','explosion','bomb']))return'IED / Explosion';if(hasAny(text,['drone','quadcopter','uav']))return'Drone / Quadcopter';if(hasAny(text,['ibo','operation','intelligence-based','raid']))return'Counterterrorism operation';if(hasAny(text,['targeted','assassinat','shot dead']))return'Targeted killing';if(hasAny(text,['ambush','attack','firing','clash']))return'Armed attack';return'Security incident'}function actor(text){if(hasAny(text,['ttp','pakistani taliban']))return'TTP';if(hasAny(text,['bla','balochistan liberation army']))return'BLA';if(hasAny(text,['security forces','ctd','police','army','ibo','operation']))return'Security forces';if(hasAny(text,['militant','armed men','terrorist']))return'Armed militants';return'Unidentified'}function severity(text,fatalities,injuries){if(fatalities>0||injuries>=3||hasAny(text,['ied','blast','explosion','killed','dead']))return'High';if(hasAny(text,['attack','ambush','operation','ibo','drone','quadcopter','damaged']))return'Medium';return'Low'}function titleFor(cat,dist,text){const first=compact(text).split('.')[0];return first&&first.length<=92?first:`${cat} reported in ${dist}`}async function xFetch(path){const response=await fetch(API+path,{headers:{Authorization:`Bearer ${TOKEN}`}});if(!response.ok)throw new Error(`X API ${response.status}: ${(await response.text()).slice(0,240)}`);return response.json()}async function main(){if(!TOKEN){console.log('X_BEARER_TOKEN is not configured; skipping X import.');out('added_count',0);return}const feed=JSON.parse(fs.readFileSync(DATA_PATH,'utf8'));const incidents=Array.isArray(feed.incidents)?feed.incidents:[];const existing=new Set(incidents.map((incident)=>incident.source_url).filter(Boolean));const user=await xFetch(`/users/by/username/${encodeURIComponent(X_USERNAME)}`);const userId=user?.data?.id;if(!userId)throw new Error(`Could not resolve X user ${X_USERNAME}`);const tweets=await xFetch(`/users/${userId}/tweets?max_results=20&exclude=retweets,replies&tweet.fields=created_at`);const added=[];for(const tweet of (tweets.data||[]).slice().reverse()){const sourceUrl=`https://x.com/${X_USERNAME}/status/${tweet.id}`;if(existing.has(sourceUrl))continue;const text=compact(tweet.text);if(!incidentLike(text))continue;const location=districtFor(text);if(!location)continue;const fatalities=casualty(text,['killed','dead','martyred']);const injuries=casualty(text,['injured','wounded']);const cat=category(text);const date=String(tweet.created_at||new Date().toISOString()).slice(0,10);added.push({id:`${date}-${slug(location.district)}-${slug(cat)}-${tweet.id}`,date,time_label:'From X post',title:titleFor(cat,location.district,text),district:location.district,province:location.province,country:'Pakistan',lat:location.lat,lng:location.lng,category:cat,actor:actor(text),status:'Initial report',severity:severity(text,fatalities,injuries),fatalities,injuries,summary:text,source:'TGD X',source_url:sourceUrl,verified:false})}if(added.length){feed.incidents=added.concat(incidents).sort((a,b)=>String(b.date||'').localeCompare(String(a.date||'')));feed.last_updated=new Date().toISOString();fs.writeFileSync(DATA_PATH,JSON.stringify(feed,null,2)+'\n')}console.log(`Added ${added.length} incident(s) from X.`);out('added_count',added.length)}main().catch((error)=>{console.error(error);process.exitCode=1});